        assert_eq!(HttpMethod::Options.as_str(), "OPTIONS");
    }

    #[test]
    fn test_http_method_padded() {
        let padded = HttpMethod::Get.padded();
        eprintln!("[TEST] Padded GET: '{}' len={}", padded, padded.len());
        assert_eq!(padded.len(), 7);
        assert!(padded.starts_with("GET"));
    }

    #[test]
    fn test_http_method_from_str() {
        eprintln!("[TEST] HttpMethod::from_str()");
        assert_eq!("GET".parse::<HttpMethod>().unwrap(), HttpMethod::Get);
        assert_eq!("post".parse::<HttpMethod>().unwrap(), HttpMethod::Post);
        assert_eq!("DELETE".parse::<HttpMethod>().unwrap(), HttpMethod::Delete);
        assert!("INVALID".parse::<HttpMethod>().is_err());
    }

    // ========== REQUEST LOG TESTS ==========

    #[test]
    fn test_request_log_new() {
        let log = RequestLog::new(
            HttpMethod::Get, "/api/users", 200, Duration::from_millis(25)
        );
        eprintln!("[TEST] RequestLog: {:?}", log);
        assert_eq!(log.method, HttpMethod::Get);
        assert_eq!(log.path, "/api/users");
        assert_eq!(log.status_code, 200);
        assert_eq!(log.status_text, "OK");
    }

    #[test]
    fn test_request_log_duration_ms() {
        let log = RequestLog::new(
            HttpMethod::Get, "/", 200, Duration::from_micros(23456)
        );
        let ms = log.duration_ms();
        eprintln!("[TEST] Duration: {} ms", ms);
        assert!((ms - 23.456).abs() < 0.001);
    }

    #[test]
    fn test_request_log_status_category() {
        eprintln!("[TEST] Status categories");
        assert_eq!(
            RequestLog::new(HttpMethod::Get, "/", 100, Duration::ZERO).status_category(),
            StatusCategory::Info
        );
        assert_eq!(
            RequestLog::new(HttpMethod::Get, "/", 200, Duration::ZERO).status_category(),
            StatusCategory::Success
        );
        assert_eq!(
            RequestLog::new(HttpMethod::Get, "/", 301, Duration::ZERO).status_category(),
            StatusCategory::Redirect
        );
        assert_eq!(
            RequestLog::new(HttpMethod::Get, "/", 404, Duration::ZERO).status_category(),
            StatusCategory::ClientError
        );
        assert_eq!(
